using System.IO;
using System.IO.Stream;
using OfficeOpenXml;
using OfficeOpenXml.ExcelPackage;
using OfficeOpenXml.ExcelRange;

/// <summary>
/// Bom Import from Excel
/// </summary>
class KJP_SM_BomImportClass extends RunBase
{
    Dialog   dialog;
    Filename filename;
    
    private ExcelRange range;
    private List headerCellList = new List(Types::String);

    private Args importArgs;
    // Define error msg list
    private List errorMsgList = new List(Types::String);
    // Define Temp data Record
    KJP_SM_BomImportTemp bomImportTmpRecord;

    // Define button name
    private const str availableTypes = '.xlsx,.xls';
    private const str okButtonName = 'OkButton';
    private const str fileUploadName = 'FileUpload';
    private const str bomImportHeaderLayout = 'KJP_SM_BomImportHeaderLayout';

    // Define Column for Excel
    private const str siteColumn = 'A';
    private const str bomVersionColumn = 'B';
    private const str bomVersionNameColumn = 'C';
    private const str parentItemColumn = 'D';
    private const str lineNumberColumn = 'E';
    private const str childItemColumn = 'F';
    private const str lineTypeColumn = 'G';
    private const str perSeriesColumn = 'H';
    private const str quantityColumn = 'I';
    private const str locationColumn = 'J';
    private const str fromDateColumn = 'K';
    private const str toDateColumn = 'L';
    private const str flushingPrincipleColumn = 'M';
    private const str scrapConstColumn = 'N';
    private const str scrapVarColumn = 'O';
    private const str vendIdColumn = 'P';
    
    // Define varrable
    private const str blank = '';
    private const int num_0 = 0;
    private const int num_1 = 1;
    private const int num_2 = 2;
    private const int num_3 = 3;
    private const int num_4 = 4;
    private const int num_5 = 5;
    private const int num_6 = 6;
    private const int num_7 = 7;
    private const int num_8 = 8;
    private const int num_9 = 9;
    private const int num_10 = 10;
    private const int num_11 = 11;
    private const int num_12 = 12;
    private const int num_13 = 13;
    private const int num_14 = 14;
    private const int num_15 = 15;
    private const int num_16 = 16;
    private const int num_20 = 20;
    private const int num_30 = 30;
    private const int num_80 = 80;
    private const int HeaderLine = 1;
    private const str backSlash = '　/　';
    private const str squareBracketL = '[';
    private const str squareBracketR = ']';
    private const str dateNullStr ='1900/01/01';

    private const real real_0 = 1.00;
    private const real real_1 = 0.1;
    private const real real_2 = 0.01;
    private const real real_3 = 0.001;
    
    // Define varrable for BOMType
    private const str itemBOMType = '品目';                           // Item
    private const str peggedSupplyBOMType = 'ペギングされた供給';      // PeggedSupply
    private const str phantomBOMType = 'ファントム';                  // Phantom
    private const str vendorBOMType = '仕入先';                       // Vendor

    // Define varrable for FlushingPrinciple
    private const str startFlushingPrinciple = '開始';                 // start
    private const str finishFlushingPrinciple = '完了';               　// finish
    private const str manualFlushingPrinciple = '手動';                 // manual
    private const str availableFlushingPrinciple = '場所で利用可';       // available

    // Define judgment Flg
    boolean siteChkFlg = true;
    boolean beforeSiteChkFlg = true;
    boolean chkSiteResult = true;

    boolean bomVersionChkFlg = true;
    boolean beforeBomVersionChkFlg = true;
    boolean chkBomVersionResult = true;

    boolean bomVersionNameChkFlg = true;
    boolean beforeBomVersionNameChkFlg = true;
    boolean chkBomVersionNameResult = true;

    boolean parentItemChkFlg = true;
    boolean beforeParentItemChkFlg = true;
    boolean chkParentItemResult = true;

    boolean lineNumberChkFlg = true;
    boolean beforeLineNumberChkFlg = true;
    boolean chkLineNumberResult = true;

    boolean childItemChkFlg = true;
    boolean beforeChildItemChkFlg = true;
    boolean chkChildItemResult = true;

    boolean lineTypeChkFlg = true;
    boolean beforeLineTypeChkFlg = true;
    boolean chkLineTypeResult = true;

    boolean perSeriesChkFlg = true;
    boolean beforePerSeriesChkFlg = true;
    boolean chkPerSeriesResult = true;

    boolean quantityChkFlg = true;
    boolean beforeQuantityChkFlg = true;
    boolean chkQuantityResult = true;

    boolean locationChkFlg = true;
    boolean beforeLocationChkFlg = true;
    boolean chkLocationResult = true;

    boolean fromDateChkFlg = true;
    boolean beforeFromDateChkFlg = true;
    boolean chkFromDateResult = true;

    boolean toDateChkFlg = true;
    boolean beforeToDateChkFlg = true;
    boolean chkToDateResult = true;

    boolean flushingPrincipleChkFlg = true;
    boolean beforeFlushingPrincipleChkFlg = true;
    boolean chkFlushingPrincipleResult = true;

    boolean scrapConstChkFlg = true;
    boolean beforeScrapConstChkFlg = true;
    boolean chkScrapConstResult = true;

    boolean scrapVarChkFlg = true;
    boolean beforeScrapVarChkFlg = true;
    boolean chkScrapVarResult = true;

    boolean vendIdChkFlg = true;
    boolean beforeVendIdChkFlg = true;
    boolean chkVendIdResult = true;

    boolean beforeCheckExcelContentResultFlg = true;
    boolean checkExcelContentResultFlg = true;
    boolean checkExcelContentFlg = true;
    boolean chkLoopFlg = true;
    boolean chkLoopResult = true;

    boolean blankFileFlg = true;
    boolean chkHeaderResult = true;

    str beforeBomId = null;
    str beforeItemId = null;
    str beforeSiteId = null;

    str beforeBomIdValue = null;
    int bomLineNumberSeq;
    int bomLineSeq;

    str beforeUniqueBomId = null;
    str beforeUniqueItemId = null;
    str beforeUniqueSiteId = null;
    boolean chkUniqueFlg = true;

}

Method.Source:
    /// <summary>
    /// Main
    /// </summary>
    /// <param name = "_args">Args</param>
    public static void main(Args _args)
    {
        KJP_SM_BomImportClass obj = new KJP_SM_BomImportClass();

        if(obj.prompt())
        {
            obj.setArgs(_args);
            obj.runOperation();
        }
    }

/// <summary>
/// set Args from
/// </summary>
/// <param name = "_args">Args</param>
public void setArgs(Args _args)
{
    importArgs = _args;
}

    /// <summary>
    /// dialog initialization
    /// </summary>
    /// <returns>Object</returns>
    public Object dialog()
    {
        DialogGroup      dialogGroup;
        FormBuildControl formBuildControl;
        FileUploadBuild  dialogFileUpload;

        dialog = super();
  
        dialog.caption("@KJP:KJP101000");
        
        dialogGroup = dialog.addGroup();
        formBuildControl = dialog.formBuildDesign().control(dialogGroup.name());
        
        dialogFileUpload = formBuildControl.addControlEx(classstr(FileUpload), fileUploadName);
        dialogFileUpload.style(FileUploadStyle::MinimalWithFilename);
        dialogFileUpload.baseFileUploadStrategyClassName(classstr(FileUploadTemporaryStorageStrategy));
        dialogFileUpload.fileTypesAccepted(availableTypes);
        
        dialogFileUpload.browseText("@KJP:KJP101464");
        dialogFileUpload.fileNameLabel("@KJP:KJP101307");

        return dialog;
    }

/// <summary>
/// dialog Post Run process
/// </summary>
/// <param name = "_dialog">DialogRunbase</param>
public void dialogPostRun(DialogRunbase _dialog)
{
    FileUpload fileUpload = this.getFormControl(_dialog, fileUploadName);
    fileUpload.notifyUploadCompleted += eventhandler(this.uploadCompleted);
    this.setDialogOkButtonEnabled(_dialog, false);
}

    /// <summary>
    /// upload Completed process
    /// </summary>
    protected void uploadCompleted()
    {
        FileUpload fileUpload = this.getFormControl(dialog, fileUploadName);
        FileUploadTemporaryStorageResult uploadResult = fileUpload.getFileUploadResult();
         
        if (uploadResult.getUploadStatus())
        {
            fileUpload.notifyUploadCompleted -= eventhandler(this.UploadCompleted);
            filename = fileUpload.fileName();

            this.setDialogOkButtonEnabled(dialog, true);
        }
        else
        {
            warning(uploadResult.getLogMessage());
        }
    }

/// <summary>
/// set Dialog Ok Button Enabled
/// </summary>
/// <param name = "_dialog">DialogRunbase</param>
/// <param name = "_isEnabled">boolean</param>
protected void setDialogOkButtonEnabled(DialogRunbase _dialog, boolean _isEnabled)
{
    FormControl okButtonControl = this.getFormControl(_dialog, okButtonName);
    if (okButtonControl)
    {
        okButtonControl.enabled(_isEnabled);
    }
}

/// <summary>
/// get Form Control
/// </summary>
/// <param name = "_dialog">DialogRunbase</param>
/// <param name = "_controlName">str</param>
/// <returns>FormControl</returns>
protected FormControl getFormControl(DialogRunbase _dialog, str _controlName)
{
    return _dialog.formRun().control(_dialog.formRun().controlId( _controlName));
}

    /// <summary>
    /// run
    /// </summary>
    public void run()
    {

        try
        {

            // read excel content
            this.processExcFile();

            if (blankFileFlg && chkHeaderResult && checkExcelContentResultFlg)
            {
                // Check if there are different SiteId or ParentItem for the same BOMVersion in the Excel.
                this.checkUniqueData();
                
                if (chkUniqueFlg)
                {
                    ttsbegin;

                    // check bomVersion data
                    this.isHaveBomVersionData();

                    if (!chkLoopFlg)
                    {
                        ttsabort;
                    }
                    else
                    {
                        str msg ;
                        msg = strFmt("@KJP:KJP500198");
                        errorMsgList.addEnd(msg);
                        ttscommit;
                    }
                }
            }
        }
        catch
        {
            // When unexpected errors occur
            errorMsgList.addEnd(Exception::Error);
        }
        finally
        {
            // Go to finish process
            this.bomImportFinishProcess();
        }
    }

    /// <summary>
    /// Choose the BOM Import upload files.
    /// </summary>
    public void processExcFile()
    {
        FileUpload          fileUploadControl;
        FileUploadTemporaryStorageResult fileUploadResult ;
        Stream   localStream;

        fileUploadControl = this.getFormControl(dialog, fileUploadName);
        fileUploadResult = fileUploadControl.getFileUploadResult();
        localStream = fileUploadResult.openResult();

        this.readExcelData(localStream);
    }

    /// <summary>
    /// Bom Import upload file check
    /// </summary>
    /// <param name = "_localStream">Stream</param>
    public void readExcelData(Stream _localStream)
    {
        int excelRowCount;
        container rangeCon;
        OfficeOpenXml.ExcelRange cell;
        str type_str = 'System.String';
        str type_dateTime = 'System.DateTime';

        ExcelPackage   package = new ExcelPackage(_localStream);
        package.Load(_localStream);
        ExcelWorksheet worksheet = package.get_Workbook().get_Worksheets().get_Item(num_1);

        ExcelAddressBase dimension = worksheet.Dimension;

        if(!dimension)
        {
            str errorMsg;
            errorMsg = strFmt("@KJP:KJP500199");
            errorMsgList.addEnd(errorMsg);

            blankFileFlg = false;
            // 2.2.5 Finish Process
            return;
        }
        else
        {
            range = worksheet.Cells;

            // Define header
            this.listHeaderCell();
            // The check of Bom Import upload file header layout
            chkHeaderResult = this.checkHeaderCell();

            if (!chkHeaderResult)
            {
                // 2.2.5 Finish Process
                return;
            }
            else
            {
                excelRowCount = dimension.End.Row - dimension.Start.Row + num_1;

                // Start with 2 due to header excluded.
                for (int i = num_2; i <= excelRowCount; i++)
                {
                    rangeCon = conNull();
                
                    rangeCon += any2Str(range.get_Item(siteColumn + int2Str(i)).Value);
                    rangeCon += any2Str(range.get_Item(bomVersionColumn + int2Str(i)).Value);
                    rangeCon += any2Str(range.get_Item(bomVersionNameColumn + int2Str(i)).Value);
                    rangeCon += any2Str(range.get_Item(parentItemColumn + int2Str(i)).Value);
                    rangeCon += any2Str(range.get_Item(lineNumberColumn + int2Str(i)).Value);
                    rangeCon += any2Str(range.get_Item(childItemColumn + int2Str(i)).Value);
                    rangeCon += any2Str(range.get_Item(lineTypeColumn + int2Str(i)).Value);
                    rangeCon += any2Str(range.get_Item(perSeriesColumn + int2Str(i)).Value);
                    rangeCon += any2Str(range.get_Item(quantityColumn + int2Str(i)).Value);
                    rangeCon += any2Str(range.get_Item(locationColumn + int2Str(i)).Value);

                    cell = range.get_Item(fromDateColumn + int2Str(i));
                    if(cell.Value == null)
                    {
                        rangeCon += any2Str(range.get_Item(fromDateColumn + int2Str(i)).Value);
                    }
                    else
                    {
                        switch(cell.Value.GetType())
                        {
                            case System.Type::GetType(type_str):
                                rangeCon += any2Str(range.get_Item(fromDateColumn + int2Str(i)).Value);
                                break;
                            case System.Type::GetType(type_dateTime):
                                rangeCon += datetime2Str(range.get_Item(fromDateColumn + int2Str(i)).Value);
                                break;
                            default:
                                rangeCon += any2Str(range.get_Item(fromDateColumn + int2Str(i)).Text);
                                break;
                        }
                    }

                    cell = range.get_Item(toDateColumn + int2Str(i));
                    if(cell.Value == null)
                    {
                        rangeCon += any2Str(range.get_Item(toDateColumn + int2Str(i)).Value);
                    }
                    else
                    {
                        switch(cell.Value.GetType())
                        {
                            case System.Type::GetType(type_str):
                                rangeCon += any2Str(range.get_Item(toDateColumn + int2Str(i)).Value);
                                break;
                            case System.Type::GetType(type_dateTime):
                                rangeCon += datetime2Str(range.get_Item(toDateColumn + int2Str(i)).Value);
                                break;
                            default:
                                rangeCon += any2Str(range.get_Item(toDateColumn + int2Str(i)).Text);
                                break;
                        }
                    }
                    rangeCon += any2Str(range.get_Item(flushingPrincipleColumn + int2Str(i)).Value);
                    rangeCon += any2Str(range.get_Item(scrapConstColumn + int2Str(i)).Value);
                    rangeCon += any2Str(range.get_Item(scrapVarColumn + int2Str(i)).Value);
                    rangeCon += any2Str(range.get_Item(vendIdColumn + int2Str(i)).Value);

                    // check excel content
                    beforeCheckExcelContentResultFlg = this.checkExcelContent(rangeCon, i);

                    // The current record of the check result.
                    // true -> add into tempList. false -> do not add into tempList then set the checkExcelContentResultFlg.
                    if (!beforeCheckExcelContentResultFlg)
                    {
                        checkExcelContentResultFlg = beforeCheckExcelContentResultFlg;
                    }
                    else
                    {
                        // Import data from excel into tempList
                        this.excelDataToTmpList(rangeCon);
                    }
                }

                if (!checkExcelContentResultFlg)
                {
                    // 2.2.5 Finish Process
                    return;

                }
            }
        }
    }

/// <summary>
/// can Run In New Session
/// </summary>
/// <returns>boolean</returns>
public boolean canRunInNewSession()
{
    return false;
}

/// <summary>
/// Define header layout
/// </summary>
private void listHeaderCell()
{
    headerCellList.addEnd(siteColumn + any2Str(HeaderLine));
    headerCellList.addEnd(bomVersionColumn + any2Str(HeaderLine));
    headerCellList.addEnd(bomVersionNameColumn + any2Str(HeaderLine));
    headerCellList.addEnd(parentItemColumn + any2Str(HeaderLine));
    headerCellList.addEnd(lineNumberColumn + any2Str(HeaderLine));
    headerCellList.addEnd(childItemColumn + any2Str(HeaderLine));
    headerCellList.addEnd(lineTypeColumn + any2Str(HeaderLine));
    headerCellList.addEnd(perSeriesColumn + any2Str(HeaderLine));
    headerCellList.addEnd(quantityColumn + any2Str(HeaderLine));
    headerCellList.addEnd(locationColumn + any2Str(HeaderLine));
    headerCellList.addEnd(fromDateColumn + any2Str(HeaderLine));
    headerCellList.addEnd(toDateColumn + any2Str(HeaderLine));
    headerCellList.addEnd(flushingPrincipleColumn + any2Str(HeaderLine));
    headerCellList.addEnd(scrapConstColumn + any2Str(HeaderLine));
    headerCellList.addEnd(scrapVarColumn + any2Str(HeaderLine));
    headerCellList.addEnd(vendIdColumn + any2Str(HeaderLine));
}

    /// <summary>
    /// Check header layout
    /// </summary>
    /// <returns>boolean</returns>
    private boolean checkHeaderCell()
    {
        boolean chkReasult = true;
        str errorMsg;

        ListEnumerator headerCellListEnumerator = headerCellList.getEnumerator();
        while (headerCellListEnumerator.moveNext())
        {
            str headerValue = KJP_CM_GeneralPurposeMaster::find(bomImportHeaderLayout
                , headerCellListEnumerator.current()).DestinationCode;
            str excelValue = range.get_Item(headerCellListEnumerator.current()).Value;

            // ファイル[A1]～[P1]の値がサイト、BOMバージョン、バージョン名称、親品目番号、行番号、子品目番号、行タイプ、生産数量、所要量、倉庫コード、開始日、終了日、部品消費ルール、定量仕損、変動仕損、仕入先では無い場合
            if (headerValue != excelValue)
            {
                errorMsg = strFmt("@KJP:KJP500200", headerCellListEnumerator.current(), headerValue);
                errorMsgList.addEnd(errorMsg);
                chkReasult = false;
            }
        }
        return chkReasult;
    }

    /// <summary>
    /// Check excel content
    /// </summary>
    /// <param name = "_con">container</param>
    /// <param name = "_row">int</param>
    /// <returns>boolean</returns>
    private boolean checkExcelContent(container _con, int _row)
    {

        // check site
        chkSiteResult = this.validateSiteId(conPeek(_con, num_1), _row);

        // check bomVersion
        chkBomVersionResult = this.validateBomVersion(conPeek(_con, num_1), conPeek(_con, num_2),conPeek(_con, num_4), _row);

        // check bomVersionName
        chkBomVersionNameResult = this.validateBomVersionName(conPeek(_con, num_3), _row);

        // check parentItem
        chkParentItemResult = this.validateParentItem(conPeek(_con, num_4), _row);

        // check lineNumber
        chkLineNumberResult = this.validateLineNumber(conPeek(_con, num_5), _row);

        // check childItem
        chkChildItemResult = this.validateChildItem(conPeek(_con, num_6), _row);

        // check lineType
        chkLineTypeResult = this.validateLineType(conPeek(_con, num_7), _row);

        // check perSeries
        chkPerSeriesResult = this.validatePerSeries(conPeek(_con, num_8), _row);

        // check quantity
        chkQuantityResult = this.validateQuantity(conPeek(_con, num_9), _row);

        // check location && check the correlation between siteId and locationId
        chkLocationResult = this.validateLocation(conPeek(_con, num_1), conPeek(_con, num_10), _row);

        // check fromDate
        chkFromDateResult = this.validateFromDate(conPeek(_con, num_11), _row);

        // check toDate
        chkToDateResult = this.validateToDate(conPeek(_con, num_11), conPeek(_con, num_12), _row);

        // check FlushingPrinciple
        chkFlushingPrincipleResult = this.validateFlushingPrinciple(conPeek(_con, num_13), _row);

        // check scrapConst
        chkScrapConstResult = this.validateScrapConst(conPeek(_con, num_14), _row);

        // check scrapVar
        chkScrapVarResult = this.validateScrapVar(conPeek(_con, num_15), _row);

        // check vendId
        chkVendIdResult = this.validateVendId(conPeek(_con, num_16),conPeek(_con, num_6), _row);

        if (chkSiteResult && chkbomVersionResult && chkBomVersionNameResult && chkParentItemResult
            && chkLineNumberResult && chkChildItemResult && chkLineTypeResult && chkPerSeriesResult
            && chkQuantityResult && chkLocationResult && chkFromDateResult && chkToDateResult
            && chkFlushingPrincipleResult && chkScrapConstResult && chkScrapVarResult && chkVendIdResult)
        {
            checkExcelContentFlg = true;
            return checkExcelContentFlg;
        }
        else
        {
            checkExcelContentFlg = false;
            return checkExcelContentFlg;
        }
    }

    /// <summary>
    /// Check excel content of siteid
    /// </summary>
    /// <param name = "_siteId">siteId</param>
    /// <param name = "_row">int</param>
    /// <returns>boolean</returns>
    private boolean validateSiteId(str _siteId, int _row)
    {

        str errorHeaderMsg = strFmt("@KJP:KJP500220",_row , "@KJP:KJP101172") ;
        str errorMandatoryMsg = strFmt("@KJP:KJP500164", "@KJP:KJP101172");
        str errorLenghMsg = strFmt("@KJP:KJP500165", "@KJP:KJP101172");
        str errorExistMsg = strFmt("@KJP:KJP500171", _siteId);
        str errorAllMsg = blank;
        int siteLengh = strLen(_siteId);

        // Mandatory check
        if(blank == _siteId)
        {
            if (blank == errorAllMsg)
            {
                errorAllMsg = errorHeaderMsg + squareBracketL + errorMandatoryMsg + squareBracketR;
            }
            else
            {
                errorAllMsg = errorAllMsg + backSlash + squareBracketL + errorMandatoryMsg + squareBracketR;
            }

            beforeSiteChkFlg = false;

        }

        // Lengh check (Max : 10)
        if(siteLengh > num_10)
        {
            if (blank == errorAllMsg)
            {
                errorAllMsg = errorHeaderMsg + squareBracketL + errorLenghMsg + squareBracketR;
            }
            else
            {
                errorAllMsg = errorAllMsg + backSlash + squareBracketL + errorLenghMsg + squareBracketR;
            }

            beforeSiteChkFlg = false;

        }

        // Exist check in InventSite Table.
        if(blank != _siteId && !InventSite::exist(_siteId))
        {
            if (blank == errorAllMsg)
            {
                errorAllMsg = errorHeaderMsg + squareBracketL + errorExistMsg + squareBracketR;
            }
            else
            {
                errorAllMsg = errorAllMsg + backSlash + squareBracketL + errorExistMsg + squareBracketR;
            }

            beforeSiteChkFlg = false;

        }

        if (blank != errorAllMsg)
        {
            errorMsgList.addEnd(errorAllMsg);
        }

        if (beforeSiteChkFlg)
        {
            return siteChkFlg;
        }
        else
        {
            siteChkFlg = beforeSiteChkFlg;
            return siteChkFlg;
        }
    }

    /// <summary>
    /// Check excel content of bomVersion
    /// </summary>
    /// <param name = "_siteId">_siteId</param>
    /// <param name = "_bomVersion">_bomVersion</param>
    /// <param name = "_parentItem">_parentItem</param>
    /// <param name = "_row">_row</param>
    /// <returns>boolean</returns>
    private boolean validateBomVersion(str _siteId, str _bomVersion, str _parentItem, int _row)
    {

        str errorHeaderMsg = strFmt("@KJP:KJP500220",_row , "@SYS67777") ;
        str errorMandatoryMsg = strFmt("@KJP:KJP500164", "@SYS67777");
        str errorLenghMsg = strFmt("@KJP:KJP500165", "@SYS67777");
        str errorCorrespondMsg = strFmt("@KJP:KJP500221",_bomVersion);
        str errorAllMsg = blank;
        int bomVersionLengh = strLen(_bomVersion);

        // Mandatory check
        if(blank == _bomVersion)
        {
            if (blank == errorAllMsg)
            {
                errorAllMsg = errorHeaderMsg + squareBracketL + errorMandatoryMsg + squareBracketR;
            }
            else
            {
                errorAllMsg = errorAllMsg + backSlash + squareBracketL + errorMandatoryMsg + squareBracketR;
            }

            beforeBomVersionChkFlg = false;

        }

        // Lengh check (Max : 20)
        if(bomVersionLengh > num_20)
        {
            if (blank == errorAllMsg)
            {
                errorAllMsg = errorHeaderMsg + squareBracketL + errorLenghMsg + squareBracketR;
            }
            else
            {
                errorAllMsg = errorAllMsg + backSlash + squareBracketL + errorLenghMsg + squareBracketR;
            }

            beforeBomVersionChkFlg = false;

        }

        // confirmation of consistency of siteId when bomVersionId exist in BOMTable.
        if(BOMTable::exist(_bomVersion) && BOMTable::find(_bomVersion).SiteId != _siteId)
        {
            if (blank == errorAllMsg)
            {
                errorAllMsg = errorHeaderMsg + squareBracketL + errorCorrespondMsg + squareBracketR;
            }
            else
            {
                errorAllMsg = errorAllMsg + backSlash + squareBracketL + errorCorrespondMsg + squareBracketR;
            }

            beforeBomVersionChkFlg = false;
        }

        BOMVersion bomVersionExist;
        select firstonly bomVersionExist
            where bomVersionExist.BOMId == _bomVersion;

        // confirmation of consistency of parentItem when bomVersionId exist in BOMVersion.
        if(bomVersionExist && bomVersionExist.ItemId != _parentItem)
        {
            if (blank == errorAllMsg)
            {
                errorAllMsg = errorHeaderMsg + squareBracketL + errorCorrespondMsg + squareBracketR;
            }
            else
            {
                errorAllMsg = errorAllMsg + backSlash + squareBracketL + errorCorrespondMsg + squareBracketR;
            }

            beforeBomVersionChkFlg = false;

