                errorAllMsg = errorHeaderMsg + squareBracketL + errorValueMsg + squareBracketR;
            }
            else
            {
                errorAllMsg = errorAllMsg + backSlash + squareBracketL + errorValueMsg + squareBracketR;
            }

            beforeScrapVarChkFlg = false;

        }

        if (blank != errorAllMsg)
        {
            errorMsgList.addEnd(errorAllMsg);
        }

        if (beforeScrapVarChkFlg)
        {
            return scrapVarChkFlg;
        }
        else
        {
            scrapVarChkFlg = beforeScrapVarChkFlg;
            return scrapVarChkFlg;
        }
    }

    /// <summary>
    /// Check excel content of vendId
    /// </summary>
    /// <param name = "_vendId">_vendId</param>
    /// <param name = "_childItemId">_childItemId</param>
    /// <param name = "_row">int</param>
    /// <returns>boolean</returns>
    private boolean validateVendId(str _vendId, str _childItemId, int _row)
    {

        str errorHeaderMsg = strFmt("@KJP:KJP500220",_row , "@SYS14048") ;
        str errorLenghMsg = strFmt("@KJP:KJP500165", "@SYS14048");
        str errorExistMsg = strFmt("@KJP:KJP500484", _vendId);
        str errorVendIdMsg = strFmt("@SYP4881414", _vendId, _childItemId, DateTimeUtil::getSystemDate(DateTimeUtil::getUserPreferredTimeZone()));
        str errorAllMsg = blank;
        int vendIdLengh = strLen(_vendId);

        // Lengh check (Max : 20)
        if (vendIdLengh > num_20)
        {
            if (blank == errorAllMsg)
            {
                errorAllMsg = errorHeaderMsg + squareBracketL + errorLenghMsg + squareBracketR;
            }
            else
            {
                errorAllMsg = errorAllMsg + backSlash + squareBracketL + errorLenghMsg + squareBracketR;
            }

            beforeVendIdChkFlg = false;

        }

        // Exist check in VendTable.
        if (blank != _vendId && !VendTable::exist(_vendId))
        {
            if (blank == errorAllMsg)
            {
                errorAllMsg = errorHeaderMsg + squareBracketL + errorExistMsg + squareBracketR;
            }
            else
            {
                errorAllMsg = errorAllMsg + backSlash + squareBracketL + errorExistMsg + squareBracketR;
            }

            beforeVendIdChkFlg = false;
        }
        else if (blank != _vendId && VendTable::exist(_vendId))
        {
            if (InventTable::find(_childItemId).PdsVendorCheckItem == PdsVendorCheckItem::NotAllowed)
            {
                if (!PdsApprovedVendorList::existValid(_childItemId, _vendId, dateNull()))
                {
                    if (blank == errorAllMsg)
                    {
                        errorAllMsg = errorHeaderMsg + squareBracketL + errorVendIdMsg + squareBracketR;
                    }
                    else
                    {
                        errorAllMsg = errorAllMsg + backSlash + squareBracketL + errorVendIdMsg + squareBracketR;
                    }
                    beforeVendIdChkFlg = false;
                }
            }
        }

        if (blank != errorAllMsg)
        {
            errorMsgList.addEnd(errorAllMsg);
        }

        if (beforeVendIdChkFlg)
        {
            return vendIdChkFlg;
        }
        else
        {
            vendIdChkFlg = beforeVendIdChkFlg;
            return vendIdChkFlg;
        }
    }

    /// <summary>
    /// Excel Data to TmpList
    /// </summary>
    /// <param name = "_con">container</param>
    private void excelDataToTmpList(container _con)
    {

        // site:Column A
        bomImportTmpRecord.Site = conPeek(_con, num_1);

        // bomVersion:Column B
        bomImportTmpRecord.BOMVersion = conPeek(_con, num_2);

        // bomVersionName:Column C
        bomImportTmpRecord.BOMVersionName = conPeek(_con, num_3);

        // parentItem:Column D
        bomImportTmpRecord.ParentItem = conPeek(_con, num_4);

        // lineNumber:Column E
        bomImportTmpRecord.LineNumber = conPeek(_con, num_5);

        // childItem:Column F
        bomImportTmpRecord.ChildItem = conPeek(_con, num_6);

        // lineType:Column G
        if ( itemBOMType == conPeek(_con, num_7))
        {
            bomImportTmpRecord.LineType = BOMType::Item;
        }
        else if (peggedSupplyBOMType == conPeek(_con, num_7))
        {
            bomImportTmpRecord.LineType = BOMType::PeggedSupply;
        }
        else if (phantomBOMType == conPeek(_con, num_7))
        {
            bomImportTmpRecord.LineType = BOMType::Phantom;
        }
        else if (vendorBOMType == conPeek(_con, num_7))
        {
            bomImportTmpRecord.LineType = BOMType::Vendor;
        }

        // perSeries:Column H
        bomImportTmpRecord.PerSeries = any2Real(conPeek(_con, num_8));

        // quantity:Column I
        bomImportTmpRecord.Quantity = any2Real(conPeek(_con, num_9));

        // location:Column J
        bomImportTmpRecord.Location = conPeek(_con, num_10);

        // fromDate:Column K
        bomImportTmpRecord.FromDate = str2Date(conPeek(_con, num_11),321);

        // toDate:Column L
        bomImportTmpRecord.ToDate = str2Date(conPeek(_con, num_12),321);

        // flushingPrinciple:Column M
        if ( startFlushingPrinciple == conPeek(_con, num_13))
        {
            bomImportTmpRecord.FlushingPrinciple = ProdFlushingPrincipBOM::Start;
        }
        else if (finishFlushingPrinciple == conPeek(_con, num_13))
        {
            bomImportTmpRecord.FlushingPrinciple = ProdFlushingPrincipBOM::Finish;
        }
        else if (manualFlushingPrinciple == conPeek(_con, num_13))
        {
            bomImportTmpRecord.FlushingPrinciple = ProdFlushingPrincipBOM::Manual;
        }
        else if (availableFlushingPrinciple == conPeek(_con, num_13))
        {
            bomImportTmpRecord.FlushingPrinciple = ProdFlushingPrincipBOM::Picked;
        }

        // ScrapConst:Column N
        bomImportTmpRecord.ScrapConst = any2Real(conPeek(_con, num_14));

        // ScrapVar:Column O
        bomImportTmpRecord.ScrapVar = any2Real(conPeek(_con, num_15));

        // VendId:Column P
        bomImportTmpRecord.VendId = conPeek(_con, num_16);

        // excel data to Temp database
        bomImportTmpRecord.insert();

    }

    /// <summary>
    /// Check if there are different SiteId or ParentItem for the same BOMVersion in the Excel.
    /// </summary>
    private void checkUniqueData()
    {
        str errorMsg;

        while select  bomImportTmpRecord
            order by bomImportTmpRecord.BOMVersion
        {
            if(beforeUniqueBomId == bomImportTmpRecord.BOMVersion )
            {
                if (beforeUniqueItemId != bomImportTmpRecord.ParentItem
                    || beforeUniqueSiteId != bomImportTmpRecord.Site)
                {
                    beforeUniqueBomId = bomImportTmpRecord.BOMVersion;
                    beforeUniqueItemId = bomImportTmpRecord.ParentItem;
                    beforeUniqueSiteId = bomImportTmpRecord.Site;
                    
                    chkUniqueFlg = false;

                    errorMsg = strFmt("@KJP:KJP500221", bomImportTmpRecord.BOMVersion) ;
                    errorMsgList.addEnd(errorMsg);

                }
                else
                {
                    beforeUniqueBomId = bomImportTmpRecord.BOMVersion;
                    beforeUniqueItemId = bomImportTmpRecord.ParentItem;
                    beforeUniqueSiteId = bomImportTmpRecord.Site;
                }
            }
            else
            {
                beforeUniqueBomId = bomImportTmpRecord.BOMVersion;
                beforeUniqueItemId = bomImportTmpRecord.ParentItem;
                beforeUniqueSiteId = bomImportTmpRecord.Site;
            }
        }
    }

    /// <summary>
    /// Check Data exist in BOMVersion or not
    /// </summary>
    private void isHaveBomVersionData()
    {
        BOMVersion bomVersionSearch;
        BOMTable bomTableSearch;

        while select  bomImportTmpRecord
            order by bomImportTmpRecord.Site
            , bomImportTmpRecord.ParentItem
            , bomImportTmpRecord.BOMVersion
            , bomImportTmpRecord.LineNumber
        {
            select firstonly bomVersionSearch
                where bomVersionSearch.BOMId == bomImportTmpRecord.BOMVersion
                && bomVersionSearch.ItemId == bomImportTmpRecord.ParentItem
                join bomTableSearch
                where bomTableSearch.BOMId == bomVersionSearch.BOMId
                && bomTableSearch.SiteId == bomImportTmpRecord.Site;

            // There are records in bomversion
            if(bomVersionSearch.RecId)
            {
                // Starting from the second record.
                if (beforeBomId == bomVersionSearch.BOMId && beforeItemId == bomVersionSearch.ItemId
                    && beforeSiteId == bomTableSearch.SiteId)
                {
                    beforeBomId = bomImportTmpRecord.BOMVersion;
                    beforeItemId = bomImportTmpRecord.ParentItem;
                    beforeSiteId = bomImportTmpRecord.Site;

                    // insert bom
                    this.insertBom(bomImportTmpRecord);

                    // Starting from the first record.
                }
                else
                {
                    beforeBomId = bomImportTmpRecord.BOMVersion;
                    beforeItemId = bomImportTmpRecord.ParentItem;
                    beforeSiteId = bomImportTmpRecord.Site;

                    //  delete bom
                    this.deleteBom(bomImportTmpRecord);

                    // insert bom
                    this.insertBom(bomImportTmpRecord);

                }

                // There is no records in bomversion
            }
            else
            {
                beforeBomId = bomImportTmpRecord.BOMVersion;
                beforeItemId = bomImportTmpRecord.ParentItem;
                beforeSiteId = bomImportTmpRecord.Site;

                // insert bomVersion
                this.insertBomVersion(bomImportTmpRecord);

                // insert bomTable
                this.insertBomTable(bomImportTmpRecord);

                // insert bom
                this.insertBom(bomImportTmpRecord);
             
            }

        }

    }

    /// <summary>
    /// insert BomVersion
    /// </summary>
    /// <param name = "_bomImportTmpSearch">KJP_SM_BomImportTemp</param>
    private void insertBomVersion(KJP_SM_BomImportTemp _bomImportTmpSearch)
    {

        BOMVersion insertBomVersionData;

        InventDim inventDimNew;

        inventDimNew.InventSiteId = _bomImportTmpSearch.Site;

        insertBomVersionData.clear();
        insertBomVersionData.BOMId = _bomImportTmpSearch.BOMVersion;
        insertBomVersionData.Name = _bomImportTmpSearch.BOMVersionName;
        insertBomVersionData.ItemId = _bomImportTmpSearch.ParentItem;
        insertBomVersionData.InventDimId = inventDim::findOrCreate(inventDimNew).inventDimId;
        insertBomVersionData.PmfTypeId = PmfBOMFormula::BOM;
        insertBomVersionData.FromQty = num_1;
        insertBomVersionData.SequenceId = num_1;

        insertBomVersionData.insert();

    }

    /// <summary>
    /// Delete Bom
    /// </summary>
    /// <param name = "_bomImportTmpSearch">KJP_SM_BomImportTemp</param>
    private void deleteBom(KJP_SM_BomImportTemp _bomImportTmpSearch)
    {
        BOM bomDelete;
        bomDelete.skipDataMethods(true);
        
        delete_from bomDelete
            where bomDelete.BOMId == _bomImportTmpSearch.BOMVersion;

    }

    /// <summary>
    /// Insert Bom
    /// </summary>
    /// <param name = "_bomImportTmpSearch">KJP_SM_BomImportTemp</param>
    private void insertBom(KJP_SM_BomImportTemp _bomImportTmpSearch)
    {

        BOM insertBomData;
        InventDim inventDimNew;
        UnitOfMeasure unitOfMeasure;
        str errorMsg;

        inventDimNew.InventSiteId = _bomImportTmpSearch.Site;
        inventDimNew.InventLocationId = _bomImportTmpSearch.Location;

        if (beforeBomIdValue != _bomImportTmpSearch.BOMVersion)
        {
            bomLineSeq = num_1 ;
            bomLineNumberSeq = num_1 ;
            beforeBomIdValue = _bomImportTmpSearch.BOMVersion;
        }

        insertBomData.clear();
        insertBomData.BOMId = _bomImportTmpSearch.BOMVersion;
        insertBomData.ItemId = _bomImportTmpSearch.ChildItem;
        insertBomData.InventDimId = inventDim::findOrCreate(inventDimNew).inventDimId;
        insertBomData.BOMQty = _bomImportTmpSearch.Quantity;
        insertBomData.BOMQtySerie = _bomImportTmpSearch.PerSeries;
        insertBomData.BOMType = _bomImportTmpSearch.LineType;
        insertBomData.ProdFlushingPrincip = _bomImportTmpSearch.FlushingPrinciple;
        insertBomData.UnitId = InventTable::find(_bomImportTmpSearch.ChildItem).bomUnitId();
        insertBomData.Position = _bomImportTmpSearch.LineNumber;
        insertBomData.FromDate = _bomImportTmpSearch.FromDate;
        insertBomData.ToDate = _bomImportTmpSearch.ToDate;
        insertBomData.Calculation = NoYes::Yes;
        insertBomData.LineNum = bomLineNumberSeq;
        insertBomData.LineCreationSequenceNumber = bomLineSeq;
        insertBomData.ScrapConst = _bomImportTmpSearch.ScrapConst;
        insertBomData.ScrapVar = _bomImportTmpSearch.ScrapVar;
        insertBomData.VendId = _bomImportTmpSearch.VendId;
        insertBomData.RoundUp = BOMRoundUp::Qty;

        unitOfMeasure = UnitOfMeasure::findBySymbol(insertBomData.UnitId);

        switch(unitOfMeasure.DecimalPrecision)
        {
            case num_0:
                insertBomData.RoundUpQty = real_0;
                break;
            case num_1:
                insertBomData.RoundUpQty = real_1;
                break;
            case num_2:
                insertBomData.RoundUpQty = real_2;
                break;
            default:
                insertBomData.RoundUpQty = real_3;
                break;
        }

        insertBomData.insert();

        bomLineSeq ++;
        bomLineNumberSeq ++;

        //the check of loop
        chkLoopResult = BOMHierarchyCheck::checkBOMCircularity(_bomImportTmpSearch.BOMVersion);

        if (!chkLoopResult)
        {
            chkLoopFlg = false;

            errorMsg = strFmt("@KJP:KJP500174", _bomImportTmpSearch.ChildItem);
            errorMsgList.addEnd(errorMsg);
        }
    }

    /// <summary>
    /// Insert BomTable
    /// </summary>
    /// <param name = "_bomImportTmpSearch">KJP_SM_BomImportTemp</param>
    private void insertBomTable(KJP_SM_BomImportTemp _bomImportTmpSearch)
    {
    
        BomTable insertBomTable;

        insertBomTable.clear();
        insertBomTable.BOMId = _bomImportTmpSearch.BOMVersion;
        insertBomTable.Name = _bomImportTmpSearch.BOMVersionName;
        insertBomTable.ItemGroupId = InventTable::find(_bomImportTmpSearch.ParentItem).itemGroupId();
        insertBomTable.SiteId = _bomImportTmpSearch.Site;
        insertBomTable.PmfBOMFormula = PmfBOMFormula::BOM;

        insertBomTable.insert();

    }

    /// <summary>
    /// Finish Process
    /// </summary>
    private void bomImportFinishProcess()
    {
        if (dialog.closedOk())
        {
            Args args = new Args();

            args.caller(importArgs);
            args.parmObject(errorMsgList);
            args.parmEnum(NoYes::No);

            new MenuFunction(menuItemDisplayStr(KJP_SM_BomImportResultPage), MenuItemType::Display).run(args);

        }
    }
